// Get all tasks
const allTasks = $input.all();

// Get client name
const clientName = $('Get Client Drive Details').item.json.clientName;

// Find specific tasks for this client
const reviewIntakeTask = allTasks.find(item => 
  item.json.name && item.json.name.includes(`1. Review Intake - ${clientName}`)
);

const discoveryCallTask = allTasks.find(item => 
  item.json.name && item.json.name.includes(`3. Discovery Call - ${clientName}`)
);

// Return task IDs or null
return [{
  json: {
    reviewIntakeTaskId: reviewIntakeTask?.json?.id || null,
    reviewIntakeTaskName: reviewIntakeTask?.json?.name || null,
    discoveryCallTaskId: discoveryCallTask?.json?.id || null,
    discoveryCallTaskName: discoveryCallTask?.json?.name || null,
    clientName: clientName,
    bothTasksFound: !!(reviewIntakeTask && discoveryCallTask)
  }
}];
